INSERT INTO client_delivery (
  delivery_id, cl_order_id, product_id, lot_no, delivery_qty, delivery_date,
  delivery_status, client_id, tracking_number,
  created_at, updated_at, is_pdf_generated
) VALUES (
 #{deliveryId}, #{clOrderId}, #{productId}, #{lotNo}, #{deliveryQty}, #{deliveryDate},
  #{deliveryStatus}, #{clientId}, #{trackingNumber},
  #{createdAt}, #{updatedAt}, #{isPdfGenerated}
)

mapper.update:
UPDATE product_stock
SET stock_qty = stock_qty - #{qty}
WHERE product_id = #{productId} AND lot_no = #{lotNo}

UPDATE product_stock
SET stock_qty = stock_qty - #{qty}
WHERE product_id = #{productId}

UPDATE client_order_detail
SET detail_status = #{status}
WHERE detail_id = #{orderDetailId}

UPDATE client_order
SET cl_order_status = #{status}
WHERE cl_order_id = #{clOrderId}

mapper.select:
SELECT cd.delivery_id, cd.cl_order_id, c.client_name AS client_name, cd.product_id, p.product_name, cd.lot_no, cd.delivery_qty, cd.delivery_date, cd.tracking_number, cd.delivery_status, cd.created_at FROM client_delivery cd JOIN product p ON cd.product_id = p.product_id JOIN client c ON cd.client_id = c.client_id
cd.delivery_status != 'CANCELLED'
AND ( cd.cl_order_id LIKE CONCAT('%', #{keyword}, '%') OR c.client_name LIKE CONCAT('%', #{keyword}, '%') OR p.product_name LIKE CONCAT('%', #{keyword}, '%') )
AND cd.delivery_date >= #{startDate} AND cd.delivery_date <= #{endDate}
ORDER BY
cd.delivery_id cd.cl_order_id c.client_name p.product_name cd.delivery_date cd.delivery_id
${sortOrder}
ORDER BY cd.delivery_id DESC
LIMIT #{pageStart}, #{perPageNum}

SELECT COUNT(*) FROM client_delivery cd JOIN product p ON cd.product_id = p.product_id JOIN client c ON cd.client_id = c.client_id
AND ( cd.cl_order_id LIKE CONCAT('%', #{keyword}, '%') OR c.client_name LIKE CONCAT('%', #{keyword}, '%') OR p.product_name LIKE CONCAT('%', #{keyword}, '%') )
AND cd.delivery_date >= #{startDate} AND cd.delivery_date <= #{endDate}

SELECT co.cl_order_id, c.client_name, p.product_id, p.product_name, cod.order_qty, cod.detail_id, co.cl_delivery_date AS cl_delivery_date, COALESCE(( SELECT SUM(remaining_qty) FROM ( SELECT pi.inbound_qty - COALESCE(SUM(po.outbound_qty), 0) AS remaining_qty FROM product_inbound pi LEFT JOIN product_outbound po ON pi.product_id = po.product_id AND pi.lot_no = po.lot_no WHERE pi.product_id = p.product_id GROUP BY pi.inbound_id, pi.inbound_qty, pi.expire_date HAVING remaining_qty > 0 ) AS available ), 0) AS stock_qty FROM client_order_detail cod JOIN client_order co ON cod.cl_order_id = co.cl_order_id JOIN client c ON co.client_id = c.client_id JOIN product p ON cod.product_id = p.product_id
co.cl_order_status = 'CONFIRMED' AND (cod.detail_status IS NULL OR cod.detail_status != 'SHIPPED')
GROUP BY co.cl_order_id, c.client_name, p.product_id, p.product_name, cod.order_qty, cod.detail_id, co.cl_delivery_date ORDER BY co.cl_delivery_date ASC LIMIT #{pageStart}, #{perPageNum}

